const parsed = $('Parse Meta event').item.json;
const errItem = $input.first().json;

let errMsg = 'Unknown error updating template status in MongoDB';
if (typeof errItem.error === 'string') {
  errMsg = errItem.error;
} else if (errItem.error && errItem.error.message) {
  errMsg = errItem.error.message;
} else if (errItem.message) {
  errMsg = errItem.message;
}

const now = new Date().toISOString();

return [{
  json: {
    organizationId: null,
    phoneNumberId: null,
    wabaId: parsed.wabaId || null,
    userId: null,
    action: 'TEMPLATE_STATUS_UPDATE',
    status: 'ERROR',
    request: {
      method: 'WEBHOOK',
      url: null,
      body: {
        waTemplateId: parsed.waTemplateId,
        templateName: parsed.templateName,
        templateLanguage: parsed.templateLanguage,
        finalStatus: parsed.finalStatus,
        reason: parsed.reason
      }
    },
    response: {
      httpStatus: 500,
      data: null
    },
    error: {
      message: errMsg,
      metaCode: null,
      metaType: null
    },
    triggeredBy: 'WEBHOOK',
    createdAt: now,
    updatedAt: now
  }
}];

