const parsed = $('Parse Meta event').item.json;

let status = parsed.finalStatus;
if (status === 'DISABLED') status = 'REJECTED';

return [{
  json: {
    'waTemplate.waTemplateId': parsed.waTemplateId,
    'waTemplate.status': status,
    'waTemplate.reason': parsed.reason || null,
    'waTemplate.category': parsed.category,
    'Status.isActive': status === 'APPROVED',
    'Status.isInert': status !== 'APPROVED'
  }
}];

const items = $input.all();
const parsed = $('Parse Meta event').item.json;

// With 'Always Output Data' enabled on the Find node, a no-match still
// produces exactly 1 item, but it's an empty placeholder ({}) rather than
// a real document -- so check for real content, not just item count.
const found = items.length > 0
  && items[0].json
  && Object.keys(items[0].json).length > 0;

return [{ json: { _found: found, ...parsed } }];

const skip = $input.first().json;
const now = new Date().toISOString();

return [{
  json: {
    organizationId: null,
    phoneNumberId: null,
    wabaId: null,
    userId: null,
    action: 'TEMPLATE_STATUS_UPDATE',
    status: 'SKIPPED',
    request: {
      method: 'WEBHOOK',
      url: null,
      body: skip
    },
    response: {
      httpStatus: 200,
      data: { reason: skip.reason }
    },
    error: null,
    triggeredBy: 'WEBHOOK',
    createdAt: now,
    updatedAt: now
  }
}];

// 

const body = $input.first().json.body || $input.first().json;

// Handle Meta webhook verification (GET challenge) — not needed here since
// n8n webhook is POST only, but guard anyway
if (!body.entry || !Array.isArray(body.entry)) {
  return [{ json: { _skip: true, reason: 'Not a valid Meta webhook payload' } }];
}

const changes = body.entry[0]?.changes || [];
const change  = changes.find(c => c.field === 'message_template_status_update');

if (!change) {
  return [{ json: { _skip: true, reason: 'No message_template_status_update field found' } }];
}

const val = change.value;

return [{
  json: {
    _skip:              false,
    waTemplateId:       String(val.message_template_id),
    templateName:       val.message_template_name,
    templateLanguage:   val.message_template_language,
    category:           val.message_template_category,
    finalStatus:        val.event,           // APPROVED | REJECTED | DISABLED | FLAGGED
    reason:             val.reason || 'NONE',
    wabaId:             body.entry[0]?.id || null
  }
}];
